import { io, Socket } from 'socket.io-client';
import { ChargerStatus } from '../types';

interface ChargerEventPayload {
  charger?: BackendCharger;
}

interface ChargersListPayload {
  chargers?: BackendCharger[];
}

interface BackendCharger {
  id: string;
  status: ChargerStatus['status'];
  voltage: number;
  current: number;
  power: number;
  temperature: number;
  errorCode?: string;
  lastUpdated: string;
}

class WebSocketService {
  private socket: Socket | null = null;
  private chargers: ChargerStatus[] = [];
  private listeners: Array<(chargers: ChargerStatus[]) => void> = [];
  private isConnected = false;

  private resolveServerUrl(): string {
    if (process.env.REACT_APP_WS_URL) {
      return process.env.REACT_APP_WS_URL;
    }

    if (typeof window !== 'undefined') {
      return window.location.origin;
    }

    return 'http://localhost:8000';
  }

  private toChargerStatus(charger: BackendCharger): ChargerStatus {
    return {
      id: charger.id,
      name: charger.id,
      status: charger.status,
      voltage: Number(charger.voltage ?? 0),
      current: Number(charger.current ?? 0),
      power: Number(charger.power ?? 0),
      temperature: Number(charger.temperature ?? 0),
      errorCode: charger.errorCode,
      lastUpdated: new Date(charger.lastUpdated),
    };
  }

  private emitChargers() {
    this.listeners.forEach((listener) => listener([...this.chargers]));
  }

  private upsertCharger(charger: ChargerStatus) {
    const idx = this.chargers.findIndex((item) => item.id === charger.id);
    if (idx >= 0) {
      this.chargers[idx] = charger;
    } else {
      this.chargers.push(charger);
    }
    this.emitChargers();
  }

  connect() {
    if (this.socket) {
      return;
    }

    this.socket = io(this.resolveServerUrl(), {
      transports: ['websocket'],
      reconnection: true,
      reconnectionAttempts: Infinity,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
    });

    this.socket.on('connect', () => {
      console.log('WebSocket connected');
      this.isConnected = true;
      this.socket?.emit('get_chargers', {});
    });

    this.socket.on('chargers_list', (payload: ChargersListPayload) => {
      const chargers = (payload?.chargers ?? []).map((item) => this.toChargerStatus(item));
      this.chargers = chargers;
      this.emitChargers();
    });

    this.socket.on('charger_updated', (payload: ChargerEventPayload) => {
      if (!payload?.charger) {
        return;
      }
      this.upsertCharger(this.toChargerStatus(payload.charger));
    });

    this.socket.on('disconnect', () => {
      console.log('WebSocket disconnected');
      this.isConnected = false;
    });

    this.socket.on('connect_error', (error) => {
      console.error('WebSocket connection error:', error);
    });
  }

  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
      this.isConnected = false;
    }
  }

  subscribe(callback: (chargers: ChargerStatus[]) => void): () => void {
    this.listeners.push(callback);
    callback([...this.chargers]);

    return () => {
      this.listeners = this.listeners.filter((cb) => cb !== callback);
    };
  }

  getConnectionStatus(): boolean {
    return this.isConnected;
  }
}

export default new WebSocketService();
